import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🎨 Dr. Palette — PhD in UX Quality & Visual Consistency (TypeScript)
 * Generated by Sovereign Forge.
 */
export class PalettePersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "palette";
        this.name = "Palette";
        this.emoji = "🎨";
        this.role = "PhD UX & Design Systems Engineer";
        this.phd_identity = "UX Quality & Visual Consistency (TypeScript)";
        this.stack = "Bun";
        this.healingPrompt = "Fix the following UI/UX or design system issue. Resolve accessibility violations and ensure design token consistency. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "color:\\s*[\"']#[0-9a-fA-F]{3,8}[\"']",
                    "issue": "Fragmentação Visual: Cor hardcoded — use design tokens.",
                    "severity": "medium"
          },
          {
                    "regex": "style\\s*=\\s*\\{\\{",
                    "issue": "Inline Style: Estilo inline dificulta manutenção e consistência.",
                    "severity": "medium"
          },
          {
                    "regex": "(?:width|height|margin|padding):\\s*\\d{2,}",
                    "issue": "Magic Number: Dimensão hardcoded — use variáveis de design system.",
                    "severity": "low"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Palette operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Palette, PhD em UX Quality & Visual Consistency (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
